## --- Part Two ---

Calculate how far you can see from each tree for its "scenic score"

Consider each tree on your map. *What is the highest scenic score possible for any tree?*

::: {#4d46fc81 .cell execution_count=3}
``` {.python .cell-code}
view = np.zeros((99,99))


def treeview(x, y):
    t = tre[x,y]
    u = 0
    d = 0
    l = 0
    r = 0
    # up
    if x == 1: 
        u = 1
    else: 
        for i in range(x-1, -1, -1):
            if t > tre[i, y]:
                u += 1
            if t <= tre[i, y]:
                u += 1
                break
    # down
    if x == 97:
        d = 1
    else: 
        for i in range(x+1, 99, 1):
            if t > tre[i, y]:
                d += 1
            if t <= tre[i, y]:
                d += 1
                break
    # left
    if y == 1:
        l = 1
    else: 
        for i in range(y-1, -1, -1):
            if t > tre[x, i]:
                l += 1
            if t <= tre[x, i]:
                l += 1
                break
    # right
    if y == 97:
        r = 1
    else: 
        for i in range(y+1, 99, 1):
            if t > tre[x, i]:
                r += 1
            if t <= tre[x, i]:
                r += 1
                break
    # return
    # print('u: ' + str(u))
    # print('d: ' + str(d))
    # print('l: ' + str(l))
    # print('r: ' + str(r))
    # print()
    return int(u * d * l * r)

for x in range(1,97): 
    for y in range(1,97):
        view[x, y] = treeview(x, y)


int(np.max(view))

